function baseInput() {
  try { return $('Validate Router Input').first().json; } catch (e) { return {}; }
}
function extractText(obj) {
  if (typeof obj === 'string') return obj;
  return obj.output
    ?? obj.text
    ?? obj.content
    ?? obj.message?.content
    ?? obj.choices?.[0]?.message?.content
    ?? obj.data?.choices?.[0]?.message?.content
    ?? obj.response?.body?.choices?.[0]?.message?.content
